pub fn compute_max_block_number_u64(start_block: u32, frequency: u32, num_calls: u32, ttl: u32) -> u64 {
    if num_calls == 0 { return 0; }
    (start_block as u64).saturating_add((frequency as u64).saturating_mul(num_calls as u64 - 1)).saturating_add(ttl as u64)
}
